@WebService(name = "OrderProcessingService", targetNamespace = "http://ecommerce.example.com/")
public class OrderProcessingService {
    
    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(@WebParam(name = "order") Order order) {
        OrderResponse response = new OrderResponse();
        response.setOrderId(order.getOrderId());
        
        try {
            BigDecimal totalAmount = calculateTotal(order);
            response.setTotalAmount(totalAmount);
            response.setStatus("SUCCESS");
            
            processOrderInDatabase(order);
            
        } catch (Exception e) {
            response.setStatus("FAILED");
            response.setTotalAmount(BigDecimal.ZERO);
        }
        
        return response;
    }
    
    private BigDecimal calculateTotal(Order order) {
        BigDecimal total = BigDecimal.ZERO;
        
        for (OrderItem item : order.getItems()) {
            BigDecimal itemTotal = item.getPrice().multiply(new BigDecimal(item.getQuantity()));
            total = total.add(itemTotal);
        }
        
        return total;
    }
    
    private void processOrderInDatabase(Order order) {
        // Simulate database processing
        System.out.println("Processing order: " + order.getOrderId() + 
                          " for customer: " + order.getCustomerName());
        
        for (OrderItem item : order.getItems()) {
            System.out.println("Item: " + item.getProductName() + 
                              ", Quantity: " + item.getQuantity() + 
                              ", Price: " + item.getPrice());
        }
    }
}